define([], function() {
    'use strict';

    /**
     * In-memory history stack for editor content.
     * Tracks both AI-applied and manual edits.
     *
     * @param {Object} cfg Configuration object.
     * @param {Function} cfg.getContent Returns current editor content string.
     * @param {Function} cfg.setContent Applies a content string to editor.
     * @param {Function} cfg.onStateChange Called with {canUndo:boolean, canRedo:boolean}.
     * @param {number} [cfg.debounceMs=600] Debounce for manual-change snapshots.
     * @constructor
     */
    function ContentEditorHistory(cfg) {
        this.getContent = cfg.getContent;
        this.setContent = cfg.setContent;
        this.onStateChange = cfg.onStateChange || function() {};
        this.debounceMs = typeof cfg.debounceMs === 'number' ? cfg.debounceMs : 600;

        this.history = [];
        this.historyIndex = -1;
        this.isApplyingSnapshot = false;
        this.manualTimer = null;
    }

    /**
     * Initialize history with the current editor state.
     */
    ContentEditorHistory.prototype.init = function() {
        var initial = this.getContent() || '';
        this.history = [initial];
        this.historyIndex = 0;
        this.notifyState();
    };

    /**
     * Push current content snapshot if it differs from current snapshot.
     * Truncates redo branch when user edits from a past state.
     *
     * @param {boolean} [force] Push even when same content.
     */
    ContentEditorHistory.prototype.pushSnapshot = function(force) {
        if (this.isApplyingSnapshot) {
            return;
        }
        var content = this.getContent() || '';
        var current = this.historyIndex >= 0 ? this.history[this.historyIndex] : '';
        if (!force && content === current) {
            this.notifyState();
            return;
        }

        this.history = this.history.slice(0, this.historyIndex + 1);
        this.history.push(content);
        this.historyIndex = this.history.length - 1;
        this.notifyState();
    };

    /**
     * Debounced snapshot for manual edits.
     */
    ContentEditorHistory.prototype.pushManualSnapshotDebounced = function() {
        var self = this;
        if (this.manualTimer) {
            window.clearTimeout(this.manualTimer);
        }
        this.manualTimer = window.setTimeout(function() {
            self.pushSnapshot(false);
            self.manualTimer = null;
        }, this.debounceMs);
    };

    /**
     * Record an AI/content programmatic replacement as a discrete snapshot.
     */
    ContentEditorHistory.prototype.recordExternalChange = function() {
        this.pushSnapshot(true);
    };

    /**
     * Undo current content.
     */
    ContentEditorHistory.prototype.undo = function() {
        if (this.historyIndex <= 0) {
            return;
        }
        this.historyIndex--;
        this.applyAtIndex(this.historyIndex);
    };

    /**
     * Redo next content.
     */
    ContentEditorHistory.prototype.redo = function() {
        if (this.historyIndex >= this.history.length - 1) {
            return;
        }
        this.historyIndex++;
        this.applyAtIndex(this.historyIndex);
    };

    /**
     * Apply snapshot at index.
     *
     * @param {number} index History index.
     */
    ContentEditorHistory.prototype.applyAtIndex = function(index) {
        if (index < 0 || index >= this.history.length) {
            return;
        }
        this.isApplyingSnapshot = true;
        this.setContent(this.history[index]);
        this.isApplyingSnapshot = false;
        this.notifyState();
    };

    /**
     * Emit current undo/redo availability.
     */
    ContentEditorHistory.prototype.notifyState = function() {
        this.onStateChange({
            canUndo: this.historyIndex > 0,
            canRedo: this.historyIndex < this.history.length - 1
        });
    };

    return ContentEditorHistory;
});
